const generateTimeSlots = () => {
  const slots = [];
  const times = ["8:00 AM", "10:00 AM", "12:00 PM", "2:00 PM", "4:00 PM"];
  const today = new Date();
  for (let d = 1; d <= 14; d++) {
    const date = new Date(today);
    date.setDate(today.getDate() + d);
    if (date.getDay() === 0) continue;
    const dateStr = date.toISOString().split("T")[0];
    times.forEach((time, i) => {
      if (Math.random() > 0.45) slots.push({ id: `${dateStr}-${i}`, date: dateStr, time, available: true });
    });
  }
  return slots;
};
const initialSlots = generateTimeSlots();

const formatDate = (s) => new Date(s + "T12:00:00").toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" });
const groupByDate = (slots) => {
  const g = {};
  slots.filter(s => s.available).forEach(s => { (g[s.date] = g[s.date] || []).push(s); });
  return g;
};

